Rule.Source:
import sailpoint.object.Certifiable;
    import sailpoint.object.EntitlementGroup;
    import sailpoint.object.ManagedAttribute;

    boolean hasNoOwner = false;
    boolean hasNoNestedEntitlements = false; //Considering how IdentityIQ generates Account Group Permissions certifications, it is unlikely this rule will ever actually exclude based on this condition. Regardless, better safe than sorry.

    if (entity != null && items != null) {

      hasNoOwner = (entity.getOwner() == null) ? true : false;
      hasNoNestedEntitlements = (entity.getAttributes().get("childGroups") == null) ? true : false;

      for (Iterator it = items.iterator(); it.hasNext();) {
        Certifiable certifiable = (Certifiable) it.next();

        if (hasNoNestedEntitlements || hasNoOwner) {

          it.remove(); //Exclude this entitlement from the certification
          itemsToExclude.add(certifiable); //Store the exclusion for easier identification of any unexpected exclusion that may occur (e.g. an entitlement that should have nested entitlements, for some reason does not)

        }

      }

      if (hasNoNestedEntitlements) {

        return "No nested entitlements to certify";

      }

      if (hasNoOwner) {

        return "Entitlement has no owner defined";

      }

    }
